{"content":"1: package oci
2: 
3: import (
4: 	"fmt"
5: 
6: 	"go.flipt.io/flipt/internal/containers"
7: 	"go.flipt.io/flipt/internal/oci/ecr"
8: 	"oras.land/oras-go/v2"
9: 	"oras.land/oras-go/v2/registry/remote/auth"
10: )
11: 
12: type AuthenticationType string
13: 
14: const (
15: 	AuthenticationTypeStatic AuthenticationType = "static"
16: 	AuthenticationTypeAWSECR AuthenticationType = "aws-ecr"
17: )
18: 
19: func (s AuthenticationType) IsValid() bool {
20: 	switch s {
21: 	case AuthenticationTypeStatic, AuthenticationTypeAWSECR:
22: 		return true
23: 	}
24: 
25: 	return false
26: }
27: 
28: // StoreOptions are used to configure call to NewStore
29: // This shouldn't be handled directory, instead use one of the function options
30: // e.g. WithBundleDir or WithCredentials
31: type StoreOptions struct {
32: 	bundleDir       string
33: 	manifestVersion oras.PackManifestVersion
34: 	auth            credentialFunc
35: }
36: 
37: // WithCredentials configures username and password credentials used for authenticating
38: // with remote registries
39: func WithCredentials(kind AuthenticationType, user, pass string) (containers.Option[StoreOptions], error) {
40: 	switch kind {
41: 	case AuthenticationTypeAWSECR:
42: 		return WithAWSECRCredentials(), nil
43: 	case AuthenticationTypeStatic:
44: 		return WithStaticCredentials(user, pass), nil
45: 	default:
46: 		return nil, fmt.Errorf("unsupported auth type %s", kind)
47: 	}
48: }
49: 
50: // WithStaticCredentials configures username and password credentials used for authenticating
51: // with remote registries
52: func WithStaticCredentials(user, pass string) containers.Option[StoreOptions] {
53: 	return func(so *StoreOptions) {
54: 		so.auth = func(registry string) auth.CredentialFunc {
55: 			return auth.StaticCredential(registry, auth.Credential{
56: 				Username: user,
57: 				Password: pass,
58: 			})
59: 		}
60: 	}
61: }
62: 
63: // WithAWSECRCredentials configures username and password credentials used for authenticating
64: // with remote registries
65: func WithAWSECRCredentials() containers.Option[StoreOptions] {
66: 	return func(so *StoreOptions) {
67: 		svc := &ecr.ECR{}
68: 		so.auth = svc.CredentialFunc
69: 	}
70: }
71: 
72: // WithManifestVersion configures what OCI Manifest version to build the bundle.
73: func WithManifestVersion(version oras.PackManifestVersion) containers.Option[StoreOptions] {
74: 	return func(s *StoreOptions) {
75: 		s.manifestVersion = version
76: 	}
77: }
