36: func TestWithManifestVersion(t *testing.T) {
37: 	o := &StoreOptions{}
38: 	WithManifestVersion(oras.PackManifestVersion1_1)(o)
39: 	assert.Equal(t, oras.PackManifestVersion1_1, o.manifestVersion)
40: }
