42: func TestAuthenicationTypeIsValid(t *testing.T) {
43: 	assert.True(t, AuthenticationTypeStatic.IsValid())
44: 	assert.True(t, AuthenticationTypeAWSECR.IsValid())
45: 	assert.False(t, AuthenticationType("").IsValid())
46: }
