333: // Build bundles the target directory Flipt feature state into the target configured on the Store
334: // It returns a Bundle which contains metadata regarding the resulting bundle details
335: func (s *Store) Build(ctx context.Context, src fs.FS, ref Reference) (Bundle, error) {
336: 	store, err := s.getTarget(ref)
337: 	if err != nil {
338: 		return Bundle{}, err
339: 	}
340: 
341: 	layers, err := s.buildLayers(ctx, store, src)
342: 	if err != nil {
343: 		return Bundle{}, err
344: 	}
345: 
346: 	desc, err := oras.PackManifest(ctx, store, s.opts.manifestVersion, MediaTypeFliptFeatures, oras.PackManifestOptions{
347: 		ManifestAnnotations: map[string]string{},
348: 		Layers:              layers,
349: 	})
350: 	if err != nil {
351: 		return Bundle{}, err
352: 	}
353: 
354: 	if ref.Reference.Reference != "" {
355: 		if err := store.Tag(ctx, desc, ref.Reference.Reference); err != nil {
356: 			return Bundle{}, err
357: 		}
358: 	}
359: 
360: 	bundle := Bundle{
361: 		Digest:     desc.Digest,
362: 		Repository: ref.Repository,
363: 		Tag:        ref.Reference.Reference,
364: 	}
365: 
366: 	bundle.CreatedAt, err = parseCreated(desc.Annotations)
367: 	if err != nil {
368: 		return Bundle{}, err
369: 	}
370: 
371: 	return bundle, nil
372: }
373: 
374: func (s *Store) buildLayers(ctx context.Context, store oras.Target, src fs.FS) (layers []v1.Descriptor, _ error) {
375: 	if err := storagefs.WalkDocuments(s.logger, src, func(doc *ext.Document) error {
376: 		payload, err := json.Marshal(&doc)
377: 		if err != nil {
378: 			return err
379: 		}
380: 
381: 		desc := v1.Descriptor{
382: 			Digest:    digest.FromBytes(payload),
383: 			Size:      int64(len(payload)),
384: 			MediaType: MediaTypeFliptNamespace,
385: 			Annotations: map[string]string{
386: 				AnnotationFliptNamespace: doc.Namespace,
387: 			},
388: 		}
389: 
390: 		s.logger.Debug("adding layer", zap.String("digest", desc.Digest.Hex()), zap.String("namespace", doc.Namespace))
391: 
392: 		if err := store.Push(ctx, desc, bytes.NewReader(payload)); err != nil && !errors.Is(err, errdef.ErrAlreadyExists) {
393: 			return err
394: 		}
395: 
396: 		layers = append(layers, desc)
397: 		return nil
398: 	}); err != nil {
399: 		return nil, err
400: 	}
401: 	return layers, nil
402: }
