89: 
90: 	fmt.Fprintf(wr, "DIGEST\tREPO\tTAG\tCREATED\t\n")
91: 	for _, bundle := range bundles {
92: 		fmt.Fprintf(wr, "%s\t%s\t%s\t%s\t\n", bundle.Digest.Hex()[:7], bundle.Repository, bundle.Tag, bundle.CreatedAt)
93: 	}
94: 
95: 	return wr.Flush()
96: }
